/* Main styles */
body {
  margin: 0;
  padding: 0;
  font-family: Arial, sans-serif;
  font-size: 16px;
  color: #333333;
  background-color: #ffffff;
}

/* Header */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 24px;
  background-color: #6366f1;
  color: white;
}

.header h1 {
  margin: 0;
  font-size: 24px;
  font-weight: 700;
}
